#ifndef class_T
#define class_T float
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifdef BLOCK_STRIDED
#define stride_val (blockdim)
#else
#define stride_val (1)
#endif

#ifdef ENABLE_HP
typedef short half2[2];
#endif

#ifdef ENABLE_HP
inline half2 conv_int(int i) {
    half2 r; r[0] = (short)i; r[1] = (short)i; return r;
}
inline half2 mad(half2 a, half2 b, half2 c) {
    half2 r; r[0] = a[0]*b[0]+c[0]; r[1] = a[1]*b[1]+c[1]; return r;
}
inline int equal(half2 a, half2 b) {
    return (a[0]==b[0]) && (a[1]==b[1]);
}
#else
inline class_T conv_int(int i) { return (class_T)i; }
inline class_T mad(class_T a, class_T b, class_T c) { return a*b+c; }
inline int equal(class_T a, class_T b) { return a==b; }
#endif

kernel void benchmark_func(class_T seed, class_T *g_data) {
    const unsigned int blockSize = blockdim;
    const unsigned int stride = stride_val;
    unsigned int idx = get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0);
    const unsigned int big_stride = get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD;

    class_T tmps[ELEMENTS_PER_THREAD];
    for(int k=0; k<FUSION_DEGREE; k++){
        for(int j=0; j<ELEMENTS_PER_THREAD; j++){
            tmps[j] = g_data[idx + j * stride + k * big_stride];
            for(int i=0; i<COMPUTE_ITERATIONS; i++){
                tmps[j] = mad(tmps[j], tmps[j], seed);
            }
        }
        class_T sum = conv_int(0);
        for(int j=0; j<ELEMENTS_PER_THREAD; j+=2)
            sum = mad(tmps[j], tmps[j+1], sum);
        if(equal(sum, conv_int(-1)))
            g_data[idx + k * big_stride] = sum;
    }
}
